sysevent_script_action.script:
var currentUser = gs.getUser();
var isAppManager = currentUser.hasRole('x_1977323_smartlic.manager');
var isAppAdmin = currentUser.hasRole('x_1977323_smartlic.admin');

if ((isAppManager || isAppAdmin) && !currentUser.hasRole('admin')) {

    var dashboardPath = '/smarthub';

    // Clear any existing Next Experience workspace landing pages
    currentUser.savePreference('now.canvas.home.url', null); 
    currentUser.savePreference('now.navigation.home.url', null);

    // Set the new target
    session.putProperty('login_redirect', dashboardPath);
    currentUser.savePreference('my_home_navigation_page', dashboardPath);
}
